const chalk = require('chalk');
const alwait = require('alwait');
const ConfigFileUtils = require('../../../../utils/ConfigFileUtils');
const { select, input } = require('@inquirer/prompts');
const ora = require('ora');
const { execFileSync } = require('child_process');
const path = require('path');

/**
 * Función para crear una nueva base de datos con configuración (Proceso completo en dos fases)
 */
async function createNewDatabase() {
    try {
        // Fase 1: configuración interactiva (addDatabaseConfig.js trae su propia UI)
        try {
            execFileSync(process.execPath, [path.join(__dirname, 'addDatabaseConfig.js')], {
                stdio: 'inherit',
                cwd: process.cwd()
            });
        } catch (error) {
            console.error(`\n${chalk.red('✖')} No se pudo completar la configuración.`);
            process.exit(1);
        }

        // Leer el nombre de la base de datos del archivo temporal
        const fs = require('fs');
        const tempFile = path.join(__dirname, '.temp_db_name');
        let databaseName;

        try {
            databaseName = fs.readFileSync(tempFile, 'utf8');
        } catch (error) {
            console.error(`\n${chalk.red('✖')} No se pudo obtener el nombre de la base de datos configurada.`);
            process.exit(1);
        } finally {
            try { fs.unlinkSync(tempFile); } catch { /* ya no existe */ }
        }

        // Fase 2: creación física (createDatabase.js trae su propia UI de resumen)
        try {
            execFileSync(process.execPath, [path.join(__dirname, 'createDatabase.js'), `--name=${databaseName}`], {
                stdio: 'inherit',
                cwd: process.cwd()
            });
        } catch (error) {
            // createDatabase.js ya imprimió el detalle del error
            process.exit(1);
        }
    } catch (error) {
        console.error(`\n${chalk.red('✖')} ${error.message}`);
        process.exit(1);
    }
}

/**
 * Función para usar una base de datos ya configurada
 * @param {string} databaseName - Nombre de la base de datos a usar
 */
async function useExistingDatabase(databaseName) {
    try {
        // Ejecutar createDatabase.js con el nombre de la base de datos existente
        // (execFileSync: el nombre no pasa por el shell, sin inyección de comandos)
        try {
            execFileSync(process.execPath, [path.join(__dirname, 'createDatabase.js'), `--name=${databaseName}`], {
                stdio: 'inherit',
                cwd: process.cwd()
            });
        } catch (error) {
            // createDatabase.js ya imprimió el detalle del error
            process.exit(1);
        }

    } catch (error) {
        console.error(`\n${chalk.red('✖')} ${error.message}`);
        process.exit(1);
    }
}

async function main() {
    //const dbcubelog = new DBCubeLogger(`❤️ ${chalk.green("Creemos una base de datos...")}\n`);
    console.clear();
    console.log(`💚 ${chalk.green("Creemos una base de datos...")}`);

    try {
        // Obtener las bases de datos configuradas
        const configuredDatabases = await ConfigFileUtils.getConfiguredDatabases();

        // Preparar las opciones para el menú
        const choices = [];

        // Agregar las bases de datos configuradas
        configuredDatabases.forEach(element => {
            choices.push({
                name: `${element.name} (${element.type})`,
                value: element.name,
                description: `${chalk.white(` Usar la configuración para la base de datos: \n 📦 ${element.name}`)}`
            });
        });
        let selected = 'create';
        if (choices.length > 0) {
            // Agregar opción para crear nueva base de datos
            choices.push({
                name: 'Crear nueva configuración\n',
                value: 'create',
                description: `📦 ${chalk.white(" Crear una nueva configuración de base de datos")}`
            });
            // Mostrar menú de selección con inquirer
            selected = await select({
                message: 'Seleccione una base de datos o cree una nueva:',
                choices: choices
            });
        }

        if (selected === 'create') {
            // El usuario quiere crear una nueva base de datos
            await createNewDatabase();
        } else {
            // El usuario quiere usar una base de datos existente
            await useExistingDatabase(selected);
        }
    } catch (error) {
        // Ctrl+C / cierre del prompt interactivo: salir en silencio, sin stack.
        if (error && (error.name === 'ExitPromptError' || /force closed/i.test(error.message || ''))) {
            console.log(`\n${chalk.gray('Cancelado.')}`);
            process.exit(0);
        }
        // Errores de config ya vienen con mensaje claro y accionable.
        console.error(`\n${chalk.red('✖')} ${error.message}`);
        process.exit(1);
    }
}

// Ejecutar el ejemplo
main().catch(error => {
    console.error(`\n${chalk.red('✖')} ${error.message}`);
    process.exit(1);
});